const urlString = $.input.urls || '';
const urls = urlString.split(',').map(u => u.trim()).filter(u => u.length > 0 && (u.startsWith('http://') || u.startsWith('https://')));
return { urls, urlCount: urls.length };

const urls = $.steps.parseUrls.output.urls;
const iterations = $.steps.scrapePages.response.iterations || [];

let allContent = '';
let successCount = 0;
let failCount = 0;

iterations.forEach((iter, i) => {
  const url = urls[i] || 'Unknown';
  const resp = (iter.scrapePage && iter.scrapePage.response && iter.scrapePage.response.data) ? iter.scrapePage.response.data : null;

  if (resp && resp.markdown) {
    successCount++;
    allContent += '=== PAGE ' + (i + 1) + ' ===\nURL: ' + url + '\n' + resp.markdown.slice(0, 3000) + '\n\n';
  } else {
    failCount++;
    allContent += '=== PAGE ' + (i + 1) + ' (FAILED) ===\nURL: ' + url + '\n\n';
  }
});

return { allContent, successCount, failCount, totalPages: urls.length };

const scraped = $.steps.compileScrapedContent.output;
const schema = $.input.extractionSchema || 'Extract all structured data';

let prompt = 'You are a web data extraction specialist. Extract structured data from the scraped web page content below.\n\n';
prompt += 'EXTRACTION GOAL: ' + schema + '\n';
prompt += 'PAGES SCRAPED: ' + scraped.successCount + ' of ' + scraped.totalPages + '\n\n';
prompt += 'SCRAPED CONTENT:\n' + scraped.allContent + '\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Extract data into a flat table structure suitable for a spreadsheet\n';
prompt += '- Each item should be one row with consistent columns\n';
prompt += '- Include the source URL for each row\n';
prompt += '- Clean and normalize the data (trim whitespace, fix encoding)\n';
prompt += '- If pricing data exists, extract as numbers without currency symbols\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "columns": ["Name", "Description", "Price", "URL", "Source"],\n';
prompt += '  "rows": [\n';
prompt += '    { "Name": "Item 1", "Description": "desc", "Price": "9.99", "URL": "link", "Source": "page url" }\n';
prompt += '  ],\n';
prompt += '  "totalItems": 0,\n';
prompt += '  "summary": "Brief summary of extracted data"\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiExtract.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { columns: [], rows: [], totalItems: 0, summary: raw }; }

const ai = $.steps.parseAI.output;
const scraped = $.steps.compileScrapedContent.output;

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Vision AI Scraping Complete', emoji: true } });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Pages Scraped:*\n' + scraped.successCount + '/' + scraped.totalPages },
  { type: 'mrkdwn', text: '*Items Extracted:*\n' + (ai.totalItems || 0) }
] });
blocks.push({ type: 'divider' });

const summaryText = (ai.summary || 'No summary available.').slice(0, 1500);
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Summary:*\n' + summaryText } });

if (ai.columns && ai.columns.length > 0) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Columns:*\n' + ai.columns.join(' | ') } });
}

if (ai.rows && ai.rows.length > 0) {
  blocks.push({ type: 'divider' });
  let sampleText = '*Sample Data (first 5 rows):*\n';
  ai.rows.slice(0, 5).forEach((row, i) => {
    const vals = Object.values(row).slice(0, 3).map(v => String(v).slice(0, 40));
    sampleText += (i + 1) + '. ' + vals.join(' | ') + '\n';
  });
  if (ai.rows.length > 5) sampleText += '... and ' + (ai.rows.length - 5) + ' more rows';
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: sampleText.slice(0, 1500) } });
}

if (scraped.failCount > 0) {
  blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: ':warning: ' + scraped.failCount + ' page(s) failed to scrape' }] });
}

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Firecrawl + Claude AI + Google Sheets' }] });

const fallback = 'Scraping: ' + (ai.totalItems || 0) + ' items from ' + scraped.successCount + ' pages saved to Sheets';
return { blocks, fallback };
